INSERT INTO supplements (id, name, category, subcategory, active_ingredients, serving_size, servings_per_container, evidence_level, safety_rating, banned_substance_risk, performance_benefits, recommended_timing, recommended_dosage, duration_of_use, drug_interactions, food_interactions, side_effects, contraindications, research_summary, key_studies, brand, cost_per_serving, third_party_tested, created_at, updated_at) VALUES (2, 'Beta-Alanine', 'endurance_enhancer', 'muscular_endurance', '{"purity":"99.5%","beta_alanine":"3g per serving"}', '3g (1 capsule)', 60, 'high', 'excellent', 'none', '["increased muscular endurance","delayed fatigue","improved sprint performance","enhanced high-intensity work capacity"]', 'divided doses throughout the day', '3-6g daily for 4-6 weeks', 'long-term safe', '["none known"]', '["none known"]', '["paresthesia (tingling)"]', '["none known"]', 'Strong evidence for beta-alanine in improving high-intensity exercise performance', '["Saunders et al. (2017) - British Journal of Sports Medicine","Saunders et al. (2012) - Journal of Strength and Conditioning Research"]', 'Generic', '0.25', TRUE, '2025-08-17T20:09:49.800Z', '2025-08-17T20:09:49.800Z');
INSERT INTO supplements (id, name, category, subcategory, active_ingredients, serving_size, servings_per_container, evidence_level, safety_rating, banned_substance_risk, performance_benefits, recommended_timing, recommended_dosage, duration_of_use, drug_interactions, food_interactions, side_effects, contraindications, research_summary, key_studies, brand, cost_per_serving, third_party_tested, created_at, updated_at) VALUES (3, 'Caffeine', 'stimulant', 'performance_stimulant', '{"purity":"99.9%","caffeine_anhydrous":"200mg per serving"}', '200mg (1 capsule)', 30, 'very_high', 'good', 'none', '["increased alertness","improved focus","enhanced endurance","reduced perceived effort"]', '30-60 minutes before training/competition', '3-6mg/kg 30-60 minutes before exercise', 'intermittent use recommended', '["heart medications","anxiety medications"]', '["none known"]', '["jitteriness","insomnia","increased heart rate"]', '["heart conditions","anxiety disorders"]', 'Extensive research supports caffeine for improved exercise performance', '["Guest et al. (2021) - Journal of the International Society of Sports Nutrition","Grgic et al. (2019) - British Journal of Sports Medicine"]', 'Generic', '0.10', TRUE, '2025-08-17T20:09:49.852Z', '2025-08-17T20:09:49.852Z');
